    function validateForm() {
        var username = document.getElementById("ctl00_ContentPlaceHolder1_txtUname").value;
        var password = document.getElementById("ctl00_ContentPlaceHolder1_txtPassword").value;

        // Check if username is a valid email address
        if (!isValidEmail(username)) {
            alert('אנא הזן כתובת דוא"ל תקנית');
            return false;
        }

        // Check if password meets minimum length requirement
        if (password.length < 4) {
            alert("סיסמה שגויה");
            return false;
        }

        return true;
    }

    function isValidEmail(email) {
        // Regular expression for validating email addresses
        var emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
        return emailRegex.test(email);
    }
</script>
